INSERT INTO public.scripts (id, titulo, categoria, curso, etapa_funil, conteudo, ativo, created_at, updated_at) VALUES ($tag$ab67e8fd-c572-45ec-9857-f9d9a068667d$tag$, $tag$Abordagem Inicial - Graduação$tag$, $tag$Atendimento inicial$tag$, $tag$Geral$tag$, $tag$Topo$tag$, $tag$Olá! Sou consultor da FICV. Vi que você se interessou por um de nossos cursos superiores. Como posso te ajudar hoje?$tag$, TRUE, $tag$2026-03-03 13:12:13.381784+00$tag$, $tag$2026-03-03 13:12:13.381784+00$tag$) ON CONFLICT (id) DO UPDATE SET titulo = EXCLUDED.titulo, categoria = EXCLUDED.categoria, curso = EXCLUDED.curso, etapa_funil = EXCLUDED.etapa_funil, conteudo = EXCLUDED.conteudo, ativo = EXCLUDED.ativo, created_at = EXCLUDED.created_at, updated_at = EXCLUDED.updated_at;
INSERT INTO public.scripts (id, titulo, categoria, curso, etapa_funil, conteudo, ativo, created_at, updated_at) VALUES ($tag$574c2a71-86d3-430c-b053-6dd25d0235f6$tag$, $tag$Quebra de Objeção: Preço$tag$, $tag$Objeções$tag$, $tag$Geral$tag$, $tag$Meio$tag$, $tag$Entendo perfeitamente sua preocupação com o investimento. Na FICV, focamos na qualidade que vai te dar o retorno profissional que você busca. Além disso, temos planos de parcelamento facilitados.$tag$, TRUE, $tag$2026-03-03 13:12:13.381784+00$tag$, $tag$2026-03-03 13:12:13.381784+00$tag$) ON CONFLICT (id) DO UPDATE SET titulo = EXCLUDED.titulo, categoria = EXCLUDED.categoria, curso = EXCLUDED.curso, etapa_funil = EXCLUDED.etapa_funil, conteudo = EXCLUDED.conteudo, ativo = EXCLUDED.ativo, created_at = EXCLUDED.created_at, updated_at = EXCLUDED.updated_at;
