INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$23e9a8a7-f2eb-4beb-bb40-820e1b15cb12$tag$, $tag$2026010200022$tag$, $tag$~ (5581997604554)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Olá, dia, tudo bem?","time":"02/01/2026 11:06:17"},{"role":"client","text":"🌟 Bom dia ~! Que alegria ter você aqui com a gente! 🙌","time":"02/01/2026 11:06:18"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"02/01/2026 11:06:21"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"02/01/2026 11:06:25"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"02/01/2026 11:06:29"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"02/01/2026 11:06:35"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"02/01/2026 11:06:41"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"02/01/2026 11:06:41"},{"role":"client","text":"Sim, concordo","time":"02/01/2026 11:07:02"},{"role":"client","text":"✅ Obrigado, ~! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"02/01/2026 11:07:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"02/01/2026 11:07:06"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"02/01/2026 11:08:56"},{"role":"client","text":"Olá! ~!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"02/01/2026 11:08:57"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"02/01/2026 11:09:01"},{"role":"client","text":"Saber sobre os cursos","time":"02/01/2026 11:09:19"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"02/01/2026 11:09:22"},{"role":"client","text":"Graduação","time":"02/01/2026 11:13:54"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"02/01/2026 11:13:58"},{"role":"client","text":"Teologia (EAD)","time":"02/01/2026 11:14:08"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"02/01/2026 11:14:08"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"02/01/2026 11:14:12"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"02/01/2026 11:14:26"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"02/01/2026 11:14:27"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 11:22:27"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"02/01/2026 11:22:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"02/01/2026 11:23:14","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Gostaria de saber a grade curricular.","time":"02/01/2026 11:25:28"},{"role":"agent","text":"*Karina Pimentel:*  Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"02/01/2026 11:25:56","feedb