INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5168ad38-7c6c-44b9-9318-61e863e56db5$tag$, $tag$2026010600012$tag$, $tag$Maria Dayane Melo do Nascimento (5582991914495)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Saber sobre os cursos","time":"06/01/2026 08:37:01"},{"role":"client","text":"🌟 Bom dia Maria Dayane Melo do Nascimento! Que alegria ter você aqui com a gente! 🙌","time":"06/01/2026 08:37:02"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"06/01/2026 08:37:06"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"06/01/2026 08:37:10"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"06/01/2026 08:37:17"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"06/01/2026 08:47:53"},{"role":"client","text":"Olá! Maria Dayane Melo do Nascimento!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"06/01/2026 08:47:53"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"06/01/2026 08:47:57"},{"role":"client","text":"Saber sobre os cursos","time":"06/01/2026 08:48:14"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"06/01/2026 08:48:18"},{"role":"client","text":"Pós-Graduação","time":"06/01/2026 08:48:51"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"06/01/2026 08:48:54"},{"role":"client","text":"Educação Cristã Clássica","time":"06/01/2026 08:49:15"},{"role":"client","text":"Formação exclus