 = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$9c19edbf-2d83-4433-8930-9f8cad25abc9$tag$, $tag$2026010800090$tag$, $tag$2020.1 TEO PRE Samara Albuquerque Matias (5583981340704)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Saber sobre os cursos","time":"08/01/2026 11:38:48"},{"role":"client","text":"🌟 Bom dia 2020.1 TEO PRE Samara Albuquerque Matias! Que alegria ter você aqui com a gente! 🙌","time":"08/01/2026 11:38:49"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"08/01/2026 11:38:53"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"08/01/2026 11:38:57"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"08/01/2026 11:39:04"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"08/01/2026 11:39:13"},{"role":"client","text":"Olá! 2020.1 TEO PRE Samara Albuquerque Matias!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"08/01/2026 11:39:14"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"08/01/2026 11:39:18"},{"role":"client","text":"Saber sobre os cursos","time":"08/01/2026 11:39:31"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"08/01/2026 11:39:35"},{"role":"client","text":"Graduação","time":"08/01/2026 11:39:46"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"08/01/2026 11:39:51"},{"role":"client","text":"Teologia (Presencial)","time":"08/01/2026 11:40:09"},{"role":"client","text":"✨ Você escolheu a modalidade presencial em João Pessoa!\nEssa é uma graduação com estrutura moderna, ensino prático desde o início e visão teológica fundamentada nas Escrituras, na tradição dos apóstolos e dos Pais da Igreja.\n\n\n 🎓 Curso reconhecido pelo MEC\n 🔠 Ensino de Grego e Hebraico\n 📌 Prática eclesiástica e liderança desde o início\n 🪙 Matrículas abertas com vagas promocionais!\n","time":"08/01/2026 11:40:10"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"08/01/2026 11:40:14"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"08/01/2026 11:43:38"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"08/01/2026 11:43:39"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"08/01/2026 11:45:01"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia Presencial* é Bacharelado e reconhecida pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato presencial as aulas acontecem de segunda à quinta-feira das 19h00 às 22h00 aqui no Polo João Pessoa, localizado na Rua Luzia Simões Bartoline, 50 - Aeroclube, João Pessoa-PB.\n\nA nossa base filosófica e teológica é fundamentada na cosmovisão cristã, utilizando o método histórico-gramatical para a interpretação das Sagradas Escrituras. Como Faculdade, diferenciamo-nos de um seminário, que geralmente segue um viés denominacional. Contamos com professores de diferentes tradições cristãs, como Presbiteriana, Batista, Adventista e Anglicana, valorizando assim a integridade intelectual. Todos os nossos docentes são especializados nas suas áreas de atuação.","time":"08/01/2026 11:45:26","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Bom dia","time":"08/01/2026