INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1e2bf5bd-f498-4a18-a89e-b04fae032d6f$tag$, $tag$2026010800200$tag$, $tag$O (5511958823756)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"08/01/2026 19:58:52"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"08/01/2026 19:58:53"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/01/2026 08:03:03"},{"role":"agent","text":"*Karina Pimentel:*   A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"09/01/2026 10:41:42","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 10% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 359,73 por mês! 🎉 Usando o cupom *BOLSA10*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n💥 Valor promocional: Semestralidade por R$ 2.158,38!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 359,73 = R$ 2.158,38\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$  431,67 = R$2.158,38\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 539,59 = R$ 2.158,38\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"09/01/2026 10:42:02","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  \n  Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"09/01/2026 16:20:24","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nO, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 16:20:26"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"12/01/2026 08:01:04"},{"role":"client","text":"Sua sessão expirou!","time":"12/01/2026 08:03:06"}]$tag$, $tag$2026-01-08 19:58:52+00$tag$, FALSE, FALSE, 6.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 5, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$92dbfe60-4550-4da5-b26e-f3e0b988bf71$tag$, $tag$2026010900006$tag$, $tag$Viviani Stefanicka (5541999828879)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Bom dia!","time":"09/01/2026 07:53:42"},{"role":"client","text":"🌟 Bom dia Viviani Stefanicka! Que alegria ter você aqui com a gente! 🙌","time":"09/01/2026 07:53:43"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"09/01/2026 07:53:47"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"09/01/2026 07:53:51"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"09/01/2026 07:53:58"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"09/01/2026 07:54:11"},{"role":"client","text":"Olá! Viviani Stefanicka!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"09/01/2026 07:54:12"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"09/01/2026 07:54:16"},{"role":"client","text":"Falar com um atendente","time":"09/01/2026 07:54:26"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"09/01/2026 07:54:27"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"09/01/2026 07:54:28"},{"role":"client","text":"Ontem falei com a Karina sobre o curso de Educação Clássica e ela me passou um voucher promocional e estou fazendo a inscrição e não dá certo.","time":"09/01/2026 07:55:24"},{"role":"client","text":"Ontem eu tentei e hoje também e não deu certo.","time":"09/01/2026 07:55:35"},{"role":"client","text":"Estou com os dados preenchidos e faltando somente o voucher para acrescentar.","time":"09/01/2026 07:56:21"},{"role":"client","text":"Preciso de ajuda para concluir a inscrição","time":"09/01/2026 07:56:31"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"09/01/2026 08:14:14"},{"role":"client","text":"Bom dia, Karina!","time":"09/01/2026 08:14:45"},{"role":"client","text":"Conforme escrevi acima, está faltando o voucher para finalizar a inscrição.","time":"09/01/2026 08:15:08"},{"role":"client","text":"O que você me enviou não está aceitando.","time":"09/01/2026 08:15:21"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"09/01/2026 08:15:48","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Te enviei o cupom e não aceitou?","time":"09/01/2026 08:16:05","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Sim","time":"09/01/2026 08:16:16"},{"role":"agent","text":"*Karina Pimentel:* Qual seu nome completo?","time":"09/01/2026 08:22:13","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Vou verificar em sistema ok!","time":"09/01/2026 08:22:19","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Viviani Pinheiro Stefanicka","time":"09/01/2026 08:22:38"},{"role":"agent","text":"*Karina Pimentel:* Qual cupom foi ofertado?","time":"09/01/2026 08:39:29","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Esse","time":"09/01/2026 08:40:16"},{"role":"agent","text":"*Karina Pimentel:* ?","time":"09/01/2026 08:47:54","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"agent","text":"*Karina Pimentel:* Não apareceu?","time":"09/01/2026 08:48:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"A minha inscrição não finalizei porque faltou o voucher","time":"09/01/2026 08:48:39"},{"role":"client","text":"Só estou aguardando isso. O passo a passo está feito e tudo preenchido","time":"09/01/2026 08:49:00"},{"role":"client","text":"Mas quando vou finalizar mostra no campo que não tenho voucher e sendo assim não terei o desconto","time":"09/01/2026 08:49:39"},{"role":"client","text":"E você me passou ontem que seria até hoje a validade do voucher","time":"09/01/2026 08:50:03"},{"role":"client","text":"ECC: *BOLSA50*","time":"09/01/2026 08:50:25"},{"role":"client","text":"Me passou esse, porém não aceita","time":"09/01/2026 08:50:40"},{"role":"agent","text":"*Karina Pimentel:* Certo!","time":"09/01/2026 08:51:42","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Mais um momento, por gentileza!","time":"09/01/2026 08:51:51","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* bit.ly/InscricaoPosECC2024","time":"09/01/2026 08:52:46","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Entre no link novamente...","time":"09/01/2026 08:52:57","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Na opção já me inscrevi!","time":"09/01/2026 08:53:09","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Veja se saiu com desconto ok!","time":"09/01/2026 08:53:18","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Pede senha","time":"09/01/2026 08:54:00"},{"role":"client","text":"Entrei","time":"09/01/2026 08:54:41"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6960eca3becfa89d7a078fa0)","time":"09/01/2026 08:55:15"},{"role":"client","text":"Entrou nessa página","time":"09/01/2026 08:55:19"},{"role":"agent","text":"*Karina Pimentel:* Tu ficou sem preencher algum campo obrigatório! ","time":"09/01/2026 08:58:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Tudo que tiver com asterisco precisa ser preenchido.","time":"09/01/2026 08:59:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6960f76a812bb86eff0362af)","time":"09/01/2026 09:41:14"},{"role":"client","text":"Feita a inscrição com sucesso.","time":"09/01/2026 09:42:06"},{"role":"client","text":"Qual seria o próximo passo?","time":"09/01/2026 09:42:28"},{"role":"agent","text":"*Karina Pimentel:* Maravilha!","time":"09/01/2026 09:48:14","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Inicio do curso em Abril!","time":"09/01/2026 09:48:28","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Será enviado o seu acesso para a Plataforma de estudo na semana de inicio do curso ok!","time":"09/01/2026 09:49:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ok","time":"09/01/2026 09:49:22"},{"role":"client","text":"Fico no aguardo","time":"09/01/2026 09:49:26"},{"role":"client","text":"E muito obrigada pela ajuda.","time":"09/01/2026 09:49:34"},{"role":"client","text":"Última pergunta, as próximas mensalidades serão  a partir de abril ou já o mês que vem?","time":"09/01/2026 09:50:21"},{"role":"agent","text":"*Karina Pimentel:* Próxima mensalidade a ser paga será em Abril. Lembrando que os pagamentos sendo feitos até o dia 10 de todo mês, o desconto será mantido! ","time":"09/01/2026 09:53:11","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Que isso, sempre que precisar pode me chamar ok!","time":"09/01/2026 09:53:30","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Muito obrigada","time":"09/01/2026 10:01:29"},{"role":"client","text":"Atendimento Finalizado!\n\nViviani Stefanicka, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"09/01/2026 10:46:53"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"09/01/2026 10:46:54"},{"role":"client","text":"Viviani Stefanicka, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"09/01/2026 11:01:54"}]$tag$, $tag$2026-01-09 07:53:42+00$tag