INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$6ea13883-f57f-4ff9-89b3-42c3a291df20$tag$, $tag$2026011400064$tag$, $tag$Richard (5583987204305)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"14/01/2026 11:14:31"},{"role":"client","text":"🌟 Bom dia Richard! Que alegria ter você aqui com a gente! 🙌","time":"14/01/2026 11:14:32"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 11:14:36"},{"role":"client","text":"Bom dia, tudo bem?","time":"14/01/2026 11:14:36"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"14/01/2026 11:14:38"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"14/01/2026 11:14:40"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"14/01/2026 11:14:44"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"14/01/2026 11:14:50"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"14/01/2026 11:14:56"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"14/01/2026 11:14:57"},{"role":"client","text":"Sim, concordo","time":"14/01/2026 11:15:08"},{"role":"client","text":"✅ Obrigado, Richard! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"14/01/2026 11:15:09"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"14/01/2026 11:15:14"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"14/01/2026 11:15:23"},{"role":"client","text":"Olá! Richard!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"14/01/2026 11:15:24"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"14/01/2026 11:15:28"},{"role":"client","text":"Falar com um atendente","time":"14/01/2026 11:15:38"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"14/01/2026 11:15:39"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"14/01/2026 11:37:53"},{"role":"client","text":"Bom dia Karina!","time":"14/01/2026 11:38:13"},{"role":"client","text":"Estou entrando em contato para apresentar uma proposta de parceria para a emissão de Carteiras de Estudante (CIE) aos alunos dessa instituição, por meio de entidade estudantil legalmente habilitada no estado da paraiba. \n\nA parceria possibilita que a instituição ofereça esse serviço aos seus estudantes de forma organizada e acessível, com retorno financeiro por cada carteira emitida. \n\nA proposta é simples, flexível e pode ser adaptada à realidade da instituição de vocês","time":"14/01/2026 11:38:38"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"14/01/2026 11:43:54","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Por gentileza enviar no email: victor@cidadeviva.org","time":"14/01/2026 11:44:05","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*  Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"14/01/2026 11:44:18","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Obrigado!","time":"14/01/2026 11:44:34"},{"role":"client","text":"Atendimento Finalizado!\n\nRichard, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"14/01/2026 11:48:39"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"14/01/2026 11:48:40"},{"role":"client","text":"5","time":"14/01/2026 11:48:57"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"14/01/2026 11:48:58"},{"role":"client","text":"Richard, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"14/01/2026 12:03:59"}]$tag$, $tag$2026-01-14 11:14:31+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact =