INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$800f37db-cd78-4eac-81ce-f93c832f08d1$tag$, $tag$2026010200064$tag$, $tag$Leonardo Felipe (5521965961790)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Fundação Cidade Viva","time":"02/01/2026 17:06:16"},{"role":"client","text":"🌟 Boa tarde Leonardo Felipe! Que alegria ter você aqui com a gente! 🙌","time":"02/01/2026 17:06:17"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"02/01/2026 17:06:21"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"02/01/2026 17:06:25"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"02/01/2026 17:06:31"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"02/01/2026 17:07:19"},{"role":"client","text":"Olá! Leonardo Felipe!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"02/01/2026 17:07:20"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"02/01/2026 17:07:24"},{"role":"client","text":"Saber sobre os cursos","time":"02/01/2026 17:07:39"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"02/01/2026 17:07:43"},{"role":"client","text":"Graduação","time":"02/01/2026 17:07:58"},{"role":"client","text":"Esses são os cursos de Graduação que temos disponíveis no momento:","time":"02/01/2026 17:08:01"},{"role":"client","text":"Teologia (EAD)","time":"02/01/2026 17:11:27"},{"role":"client","text":"📚 A graduação EAD em Teologia é ideal para quem busca flexibilidade e profundidade bíblica onde estiver.\n✨ Estude no seu ritmo, com uma formação teológica séria e completa:\n 🧠 Cosmovisão Cristã\n 🔠 Grego e Hebraico\n 💻 Plataforma moderna e aulas dinâmicas\n 🤝 Mentoria, iniciação científica e prática ministerial\n","time":"02/01/2026 17:11:28"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"02/01/2026 17:11:32"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"02/01/2026 17:12:21"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"02/01/2026 17:12:22"},{"role":"client","text":"Ok","time":"02/01/2026 17:14:30"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 17:21:16"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"02/01/2026 17:21:45","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"02/01/2026 17:22:08","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Entendi!","time":"02/01/2026 17:33:42"},{"role":"client","text":"Tem a grade das aulas e o nome dos professores?","time":"02/01/2026 17:33:57"},{"role":"client","text":"Quero fazer a minha matrícula agora em janeiro para aproveitar o desy","time":"02/01/2026 17:34:25"},{"role":"agent","text":"*Karina Pimentel:*    Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"02/01/2026 17:35:02","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Como faço para fazer a inscrição?","time":"02/01/2026 17:36:49"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar a forma de ingresso ok!","time":"02/01/2026 17:37:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"02/01/2026 17:38:02","feedback":"🚩 S